/**
 * Injects a release signing config into the Android project generated by
 * `expo prebuild`. Idempotent and deterministic.
 *
 * The release signingConfig reads its values from environment variables so no
 * secret is ever written into a committed file:
 *   HYDRIVO_STORE_FILE      (relative to android/app, e.g. "hydrivo-release.p12")
 *   HYDRIVO_STORE_PASSWORD
 *   HYDRIVO_KEY_ALIAS
 *   HYDRIVO_KEY_PASSWORD
 *
 * Run from the project root AFTER `expo prebuild --platform android`.
 */
const fs = require("fs");
const path = require("path");

const gradlePath = path.join(__dirname, "..", "android", "app", "build.gradle");

if (!fs.existsSync(gradlePath)) {
  console.error("[apply-android-signing] android/app/build.gradle not found. Run expo prebuild first.");
  process.exit(1);
}

let gradle = fs.readFileSync(gradlePath, "utf8");

if (gradle.includes("signingConfigs.release")) {
  console.log("[apply-android-signing] Release signing already configured. Skipping.");
  process.exit(0);
}

const releaseSigningBlock = `        release {
            def storeFilePath = System.getenv("HYDRIVO_STORE_FILE") ?: "hydrivo-release.p12"
            storeFile file(storeFilePath)
            storePassword System.getenv("HYDRIVO_STORE_PASSWORD")
            keyAlias System.getenv("HYDRIVO_KEY_ALIAS")
            keyPassword System.getenv("HYDRIVO_KEY_PASSWORD")
            storeType "PKCS12"
        }
`;

// 1) Insert the release signingConfig right after the "signingConfigs {" line.
const signingConfigsAnchor = /signingConfigs\s*\{\s*\n/;
if (!signingConfigsAnchor.test(gradle)) {
  console.error("[apply-android-signing] Could not find signingConfigs block.");
  process.exit(1);
}
gradle = gradle.replace(signingConfigsAnchor, (match) => match + releaseSigningBlock);

// 2) Point the release buildType at signingConfigs.release.
if (gradle.includes("signingConfig signingConfigs.debug")) {
  // Replace only the one inside buildTypes.release. The debug buildType keeps
  // its own signingConfig; we target the release occurrence which appears after
  // "release {" inside buildTypes.
  gradle = gradle.replace(
    /(buildTypes\s*\{[\s\S]*?release\s*\{[\s\S]*?)signingConfig\s+signingConfigs\.debug/,
    "$1signingConfig signingConfigs.release"
  );
} else {
  console.warn("[apply-android-signing] Release buildType signingConfig line not found; leaving as-is.");
}

fs.writeFileSync(gradlePath, gradle, "utf8");
console.log("[apply-android-signing] Release signing config applied to android/app/build.gradle.");
